import Sidebar from '../../components/sidebar';


const AdminDashboard = () => {
  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <Sidebar />

      {/* Main Content */}
      <div className="ml-64 flex-1 p-8">
        <h1 className="text-3xl font-bold text-gray-800 mb-6">
          Welcome to Admin Dashboard
        </h1>

        {/* Dashboard Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition">
            <h2 className="text-xl font-semibold mb-2 text-gray-700">Total Categories</h2>
            <p className="text-3xl font-bold text-blue-600">12</p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition">
            <h2 className="text-xl font-semibold mb-2 text-gray-700">Total Blogs</h2>
            <p className="text-3xl font-bold text-green-600">34</p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition">
            <h2 className="text-xl font-semibold mb-2 text-gray-700">Admins</h2>
            <p className="text-3xl font-bold text-red-600">1</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
